import type { Actor, Combat, Item, PermissionName } from "@open-tabletop/core";

export interface JsonSchema {
  $schema?: string;
  title?: string;
  type: string;
  properties?: Record<string, JsonSchema>;
  required?: string[];
  items?: JsonSchema;
}

export interface SystemManifest {
  id: string;
  name: string;
  version: string;
  compatibleCore: string;
  entrypoints: {
    client?: string;
    server?: string;
  };
  schemas: {
    actor: string;
    item: string;
  };
  permissions: PermissionName[];
}

export const DND_5E_SRD_SYSTEM_ID = "dnd-5e-srd";
export const DND_5E_SRD_VERSION = "SRD 5.2.1";

const DND_5E_SRD_CANTRIP_D6_SCALING = { level5: "2d6", level11: "3d6", level17: "4d6" };
const DND_5E_SRD_CANTRIP_D8_SCALING = { level5: "2d8", level11: "3d8", level17: "4d8" };
const DND_5E_SRD_CANTRIP_D10_SCALING = { level5: "2d10", level11: "3d10", level17: "4d10" };
const DND_5E_SRD_CANTRIP_D12_SCALING = { level5: "2d12", level11: "3d12", level17: "4d12" };

export interface ActorSheetRegistration {
  systemId: string;
  actorType: string;
  componentId: string;
}

export interface DiceFormulaRegistration {
  systemId: string;
  id: string;
  label: string;
  formula: string;
}

export interface QuickRoll {
  id: string;
  label: string;
  formula: string;
  metadata?: Record<string, unknown>;
}

export interface CharacterTemplateItem {
  entryId: string;
  quantity?: number;
  data?: Record<string, unknown>;
}

export interface CharacterTemplate {
  id: string;
  systemId: string;
  name: string;
  summary: string;
  actorType: string;
  data: Record<string, unknown>;
  items: CharacterTemplateItem[];
}

export interface Dnd5eSrdCharacterBackground {
  id: string;
  name: string;
  abilityScores: string[];
  feat: string;
  skillProficiencies: string[];
  toolProficiencies: string[];
  startingGp: number;
  source: typeof DND_5E_SRD_VERSION;
}

export interface Dnd5eSrdCharacterSpecies {
  id: string;
  name: string;
  creatureType: "Humanoid";
  size: string;
  speed: number;
  traits: string[];
  senses?: string[];
  source: typeof DND_5E_SRD_VERSION;
}

export interface Dnd5eSrdCharacterOrigins {
  backgrounds: Dnd5eSrdCharacterBackground[];
  species: Dnd5eSrdCharacterSpecies[];
  elfLineages: Array<{ id: string; name: string; cantrip: string; level3Spell: string; level5Spell: string }>;
  gnomeLineages: Array<{ id: string; name: string }>;
  tieflingLegacies: Array<{ id: string; name: string; resistance: string }>;
  highElfCantrips: string[];
  skills: Array<{ id: string; label: string; ability: string }>;
  originFeats: string[];
  spellcastingAbilities: string[];
}

export interface Dnd5eSrdCharacterOriginOptions {
  backgroundId?: string;
  speciesId?: string;
  abilityScoreIncreases?: unknown;
  skillProficiency?: string;
  originFeat?: string;
  elfLineage?: string;
  elfCantrip?: string;
  gnomeLineage?: string;
  tieflingLegacy?: string;
  speciesSpellcastingAbility?: string;
}

export interface Dnd5eSrdCharacterOriginBuild {
  data: Record<string, unknown>;
  items: CharacterTemplateItem[];
  background: Dnd5eSrdCharacterBackground;
  species: Dnd5eSrdCharacterSpecies;
}

export interface CharacterImportInput {
  name?: unknown;
  data?: Record<string, unknown>;
  items?: unknown;
  conditions?: unknown;
}

export interface CharacterImportResult {
  systemId: string;
  actorType: string;
  name: string;
  data: Record<string, unknown>;
  items: CharacterTemplateItem[];
  warnings: string[];
}

export interface AdvancementOption {
  id: string;
  systemId: string;
  name: string;
  summary: string;
  nextValue: number;
}

export type SystemRestType = "short" | "long";

export interface SystemRestOptions {
  arcaneRecovery?: Record<string, number>;
}

export interface SystemRestResult {
  systemId: string;
  actorId: string;
  restType: SystemRestType;
  summary: string;
  recovered: Record<string, unknown>;
  removedConditions: AppliedCondition[];
  data: Record<string, unknown>;
}

export type SystemActionConsumptionType = "spellSlot" | "resource" | "strain" | "itemQuantity" | "composure";

export interface SystemActionConsumption {
  type: SystemActionConsumptionType;
  key: string;
  label: string;
  amount: number;
  remaining: number;
}

export interface SystemActionUseOptions {
  spellSlotLevel?: number;
  resourceAmount?: number;
  useFreeResource?: boolean;
}

export interface SystemActionUseResult {
  systemId: string;
  actorId: string;
  rollId: string;
  slotLevel?: number;
  consumed: SystemActionConsumption[];
  data: Record<string, unknown>;
  items: Item[];
}

export type RulesResolutionCommitMode = "commit" | "preview";
export type RulesSaveOutcome = "success" | "failure";
export type RulesD20Mode = "normal" | "advantage" | "disadvantage";

export interface RulesResolutionTargetInput {
  actor: Actor;
  items?: Item[];
  saveOutcome?: RulesSaveOutcome;
  rollTotal?: number;
  damageTaken?: number;
}

export interface RulesResolverOptions extends SystemActionUseOptions {
  consumeResources?: boolean;
  applyEffect?: boolean;
  commit?: boolean;
  effectChoice?: string;
  saveOutcomes?: Record<string, RulesSaveOutcome>;
  reactionUse?: boolean;
  rechargeCheck?: number;
}

export interface RulesResolutionRoll {
  rollId: string;
  label: string;
  baseFormula: string;
  formula: string;
  targetActorId?: string;
  d20Mode?: RulesD20Mode;
  advantageSources: string[];
  disadvantageSources: string[];
  saveOutcome?: RulesSaveOutcome;
}

export interface RulesResolutionActorUpdate {
  actorId: string;
  before: Record<string, unknown>;
  after: Record<string, unknown>;
  reason: string;
}

export interface RulesResolutionConditionChange {
  actorId: string;
  operation: "apply" | "remove" | "startConcentration" | "replaceConcentration" | "breakConcentration" | "expire";
  conditionId?: string;
  conditionName?: string;
  duration?: string;
  durationRounds?: number;
  expiresAtRound?: number;
  repeatSave?: string;
  reason: string;
}

export interface RulesResolutionPendingSave {
  actorId: string;
  ability: string;
  dc?: number;
  reason: string;
  success?: unknown;
  requiredForCommit?: boolean;
  recurring?: boolean;
  timing?: string;
  conditionIds?: string[];
}

export interface RulesResolutionEffectResult {
  type: "damage" | "healing" | "condition" | "utility";
  targetActorId: string;
  targetActorName: string;
  pool?: string;
  amount?: number;
  before?: number | string[];
  after?: number | string[];
  max?: number;
  damageType?: string;
  damageTypes?: string[];
  effectChoice?: string;
  choiceKind?: RulesResolutionChoice["kind"];
  resistance?: string[];
  immunity?: string[];
  vulnerability?: string[];
  duration?: string;
  conditionId?: string;
  conditionName?: string;
  alreadyPresent?: boolean;
}

export interface RulesResolutionPendingReaction {
  actorId: string;
  reason: string;
  actionRollId?: string;
}

export interface RulesResolutionChoice {
  kind: "effect" | "damageType" | "resistance" | "manual";
  reason: string;
  options: string[];
}

export interface RulesResolutionBlocked {
  code: string;
  reason: string;
}

export interface RulesResolutionAuditEvent {
  code: string;
  actorId: string;
  targetActorId?: string;
  rollId: string;
  message: string;
  data?: Record<string, unknown>;
}

export interface RulesActionResolutionResult {
  systemId: string;
  actorId: string;
  rollId: string;
  commitMode: RulesResolutionCommitMode;
  action: {
    label: string;
    kind: "action" | "bonusAction" | "reaction" | "free";
    metadata: Record<string, unknown>;
  };
  rolls: RulesResolutionRoll[];
  resourceConsumption: SystemActionConsumption[];
  usage?: SystemActionUseResult;
  actorUpdates: RulesResolutionActorUpdate[];
  itemUpdates: Item[];
  effects: RulesResolutionEffectResult[];
  conditions: RulesResolutionConditionChange[];
  pendingSaves: RulesResolutionPendingSave[];
  pendingReactions: RulesResolutionPendingReaction[];
  warnings: string[];
  auditEvents: RulesResolutionAuditEvent[];
  blocked?: RulesResolutionBlocked;
  pendingChoice?: RulesResolutionChoice;
  manualResolutionRequired?: {
    reason: string;
    metadata: Record<string, unknown>;
  };
  attunement?: Dnd5eSrdAttunementState;
}

export interface Dnd5eSrdActionResolutionInput {
  actor: Actor;
  items?: Item[];
  roll: QuickRoll;
  targets?: RulesResolutionTargetInput[];
  combat?: Combat;
  options?: RulesResolverOptions;
  now?: string;
}

export interface Dnd5eSrdConcentrationDamageResult {
  data: Record<string, unknown>;
  pendingSave?: RulesResolutionPendingSave;
  condition?: RulesResolutionConditionChange;
  auditEvent?: RulesResolutionAuditEvent;
}

export interface Dnd5eSrdAttunementState {
  limit: number;
  attunedItemIds: string[];
  overLimitBy: number;
  canAttuneMore: boolean;
}

export interface Dnd5eSrdEquipmentPurchaseResult {
  systemId: typeof DND_5E_SRD_SYSTEM_ID;
  actorId: string;
  entryId: string;
  quantity: number;
  unitCostGp: number;
  totalCostGp: number;
  currency: Record<string, number>;
  data: Record<string, unknown>;
  itemData: Record<string, unknown>;
}

