export function dnd5eSrdActionRolls(actor: Actor, items: Item[] = []): QuickRoll[] {
  const actionItems = dnd5eSrdActionAvailableItems(actor, items);
  const attacksPerAction = dnd5eSrdAttacksPerAction(actor);
  const attackRolls = dnd5eSrdAttackRolls(actor, actionItems, attacksPerAction);
  const effectRolls = dnd5eSrdEffectRolls(actor, actionItems);
  const damageAndEffectRolls = genericFantasyActionRolls(actor, actionItems).map((roll) => {
    const metadata = dnd5eSrdGenericActionRollMetadata(actor, actionItems, roll);
    const rollWithMetadata = Object.keys(metadata).length > 0 ? { ...roll, metadata: { ...roll.metadata, ...metadata } } : roll;
    const martialArtsFormula = dnd5eSrdMonkWeaponDamageFormulaForRoll(actor, actionItems, roll.id);
    const nextRoll = martialArtsFormula ? { ...rollWithMetadata, formula: martialArtsFormula, metadata: { ...rollWithMetadata.metadata, martialArts: { die: dnd5eSrdMartialArtsDie(actor), dexterousAttacks: true } } } : rollWithMetadata;
    if (attacksPerAction <= 1 || !dnd5eSrdIsWeaponDamageRoll(actor, actionItems, roll.id)) return nextRoll;
    return { ...nextRoll, metadata: { ...nextRoll.metadata, attacksPerAction, feature: "Extra Attack" } };
  });
  return [...attackRolls, ...effectRolls, ...damageAndEffectRolls];
}

function dnd5eSrdGenericActionRollMetadata(actor: Actor, items: Item[], roll: QuickRoll): Record<string, unknown> {
  const item = items.find((candidate) => roll.id === `${candidate.type === "spell" ? "spell" : "item"}-${candidate.id}-damage` || roll.id === `${candidate.type === "spell" ? "spell" : "item"}-${candidate.id}-secondary-damage` || roll.id === `${candidate.type === "spell" ? "spell" : "item"}-${candidate.id}-versatile-damage` || roll.id === `${candidate.type === "spell" ? "spell" : "item"}-${candidate.id}-healing`);
  if (!item) return {};
  const data = recordValue(item.data);
  const metadata: Record<string, unknown> = {};
  const isSecondaryDamage = roll.id.endsWith("-secondary-damage");
  const isDamage = roll.id.endsWith("-damage");
  const isHealing = roll.id.endsWith("-healing");
  let hasResolutionMetadata = false;
  if (isDamage) {
    const damageType = stringValue(isSecondaryDamage ? data.secondaryDamageType : data.damageType);
    const damageTypes = normalizeStringArray(data.damageTypes);
    const damageTypeOptions = normalizeStringArray(data.damageTypeOptions);
    if (!isSecondaryDamage && damageTypes.length > 0) {
      metadata.damageTypes = damageTypes;
      hasResolutionMetadata = true;
    }
    if (!isSecondaryDamage && damageTypeOptions.length > 0) {
      metadata.damageTypeOptions = damageTypeOptions;
      hasResolutionMetadata = true;
    }
    const save = dnd5eSrdEffectSaveMetadata(actor, data, item.type === "spell");
    if (Object.keys(save).length > 0) {
      metadata.save = save;
      hasResolutionMetadata = true;
    }
    if (hasResolutionMetadata && damageType) metadata.damageType = damageType;
  }
  if ((isDamage || isHealing) && hasResolutionMetadata) {
    const action = stringValue(data.action);
    const range = stringValue(data.range);
    const area = stringValue(data.area);
    const duration = stringValue(data.duration);
    if (action) metadata.action = action;
    if (range) metadata.range = range;
    if (area) metadata.area = area;
    if (duration) metadata.duration = duration;
    if (booleanValue(data.concentration)) metadata.concentration = true;
  }
  return metadata;
}

function dnd5eSrdActionAvailableItems(actor: Actor, items: Item[]): Item[] {
  const level = Math.max(1, Math.floor(numericValue(actor.data.level, 1)));
  return items.filter((item) => {
    if (!itemBelongsToActor(actor, item)) return false;
    const minimumCharacterLevel = numericValue(recordValue(item.data).minimumCharacterLevel, Number.NaN);
    return !Number.isFinite(minimumCharacterLevel) || level >= minimumCharacterLevel;
  });
}

function dnd5eSrdAttackRolls(actor: Actor, items: Item[], attacksPerAction = dnd5eSrdAttacksPerAction(actor)): QuickRoll[] {
  return items.filter((item) => itemBelongsToActor(actor, item)).flatMap((item) => {
    const data = recordValue(item.data);
    if (item.type === "spell" && booleanValue(data.spellAttack)) return [dnd5eSrdSpellAttackRoll(actor, items, item, data)];
    if (item.type !== "spell" && dnd5eSrdIsWeaponData(data) && stringValue(data.damage)) return [dnd5eSrdWeaponAttackRoll(actor, items, item, data, attacksPerAction)];
    return [];
  });
}

function dnd5eSrdWeaponAttackRoll(actor: Actor, items: Item[], item: Item, data: Record<string, unknown>, attacksPerAction: number): QuickRoll {
  const ability = dnd5eSrdWeaponAttackAbility(actor, data);
  const conditionRoll = dnd5eSrdD20Automation(actor, "attack-roll", ability);
  const abilityBonus = genericFantasyAttributeModifier(actor, ability);
  const proficiencyMultiplier = dnd5eSrdWeaponProficiencyMultiplier(actor, items, data);
  const proficiencyBonus = dnd5eSrdProficiencyBonus(actor) * proficiencyMultiplier;
  const itemBonus = numericValue(data.attackBonus, 0);
  const metadata: Record<string, unknown> = {
    ...conditionRoll.metadata,
    attackType: "weapon",
    ability,
    proficient: proficiencyMultiplier > 0,
    proficiencyBonus
  };
  const weaponKind = stringValue(data.weaponKind);
  const weaponCategory = stringValue(data.weaponCategory);
  const range = stringValue(data.range);
  const mastery = stringValue(data.mastery);
  if (weaponKind) metadata.weaponKind = weaponKind;
  if (weaponCategory) metadata.weaponCategory = weaponCategory;
  if (range) metadata.range = range;
  if (mastery) metadata.mastery = mastery;
  if (itemBonus !== 0) metadata.itemBonus = itemBonus;
  const championCritical = dnd5eSrdChampionCriticalMetadata(actor);
  if (championCritical.minimumD20 < 20) {
    metadata.criticalRange = championCritical;
    metadata.criticalHitOn = championCritical.range;
  }
  if (attacksPerAction > 1) {
    metadata.attacksPerAction = attacksPerAction;
    metadata.feature = "Extra Attack";
  }
  return {
    id: `item-${item.id}-attack`,
    label: `${item.name} Attack`,
    formula: `${conditionRoll.d20}${formatSignedNumber(abilityBonus + proficiencyBonus + itemBonus + conditionRoll.modifier)}`,
    metadata
  };
}

function dnd5eSrdSpellAttackRoll(actor: Actor, items: Item[], item: Item, data: Record<string, unknown>): QuickRoll {
  const className = stringValue(actor.data.class) || "Fighter";
  const ability = stringValue(data.spellcastingAbility) || dnd5eSrdPrimaryAbility(className);
  const conditionRoll = dnd5eSrdD20Automation(actor, "attack-roll", ability);
  const abilityBonus = genericFantasyAttributeModifier(actor, ability);
  const proficiencyBonus = dnd5eSrdProficiencyBonus(actor);
  const equippedBonus = dnd5eSrdEquippedItemNumericBonus(actor, items, "spellAttackBonus");
  const directBonus = numericValue(data.spellAttackBonus, 0);
  const itemBonus = equippedBonus.total + directBonus;
  const metadata: Record<string, unknown> = {
    ...conditionRoll.metadata,
    attackType: "spell",
    ability,
    proficiencyBonus
  };
  const spellLevel = numericValue(data.level, Number.NaN);
  const range = stringValue(data.range);
  const damageType = stringValue(data.damageType);
  const speciesSpellResource = stringValue(data.speciesSpellResource);
  if (Number.isFinite(spellLevel)) metadata.spellLevel = spellLevel;
  if (range) metadata.range = range;
  if (damageType) metadata.damageType = damageType;
  if (itemBonus !== 0) metadata.itemBonus = itemBonus;
  if (equippedBonus.itemIds.length > 0) metadata.itemBonusItemIds = equippedBonus.itemIds;
  if (booleanValue(data.speciesSpell)) metadata.speciesSpell = true;
  if (speciesSpellResource) metadata.freeCastResource = speciesSpellResource;
  return {
    id: `spell-${item.id}-attack`,
    label: `${item.name} Attack`,
    formula: `${conditionRoll.d20}${formatSignedNumber(abilityBonus + proficiencyBonus + itemBonus + conditionRoll.modifier)}`,
    metadata
  };
}

function dnd5eSrdEffectRolls(actor: Actor, items: Item[]): QuickRoll[] {
  return items.filter((item) => itemBelongsToActor(actor, item)).flatMap((item) => {
    if (item.type !== "spell" && item.type !== "item") return [];
    const data = recordValue(item.data);
    if (!dnd5eSrdHasEffectRollData(data)) return [];
    return [dnd5eSrdEffectRoll(actor, item, data)];
  });
}

function dnd5eSrdHasEffectRollData(data: Record<string, unknown>): boolean {
  if (stringValue(data.damageFormula) || stringValue(data.healingFormula)) return false;
  return Boolean(
    stringValue(data.bonusFormula) ||
    stringValue(data.penaltyFormula) ||
    stringValue(data.recurringHealingFormula) ||
    stringValue(data.condition) ||
    stringValue(data.healing) ||
    normalizeStringArray(data.conditionsEnded).length > 0 ||
    normalizeStringArray(data.effects).length > 0 ||
    normalizeStringArray(data.advantageAbilityChecks).length > 0 ||
    normalizeStringArray(data.disadvantageAbilityChecks).length > 0 ||
    normalizeStringArray(data.advantageSavingThrows).length > 0 ||
    normalizeStringArray(data.disadvantageSavingThrows).length > 0 ||
    normalizeStringArray(data.blockedBy).length > 0 ||
    (booleanValue(data.consumable) && normalizeStringArray(data.resistance).length > 0) ||
    (booleanValue(data.consumable) && normalizeStringArray(data.resistanceChoice).length > 0) ||
    normalizeStringArray(data.resistanceChoices).length > 0 ||
    (Array.isArray(data.effectOptions) && data.effectOptions.length > 0) ||
    (booleanValue(data.consumable) && normalizeStringArray(data.skillAdvantage).length > 0) ||
    stringValue(data.damageBonusFormula) ||
    stringValue(data.damagePenaltyFormula) ||
    stringValue(data.endsCondition) ||
    (booleanValue(data.consumable) && Object.keys(recordValue(data.abilityScoreSet)).length > 0) ||
    Object.keys(recordValue(data.upcastTargets)).length > 0 ||
    Object.keys(recordValue(data.spellcastingAbilityCheck)).length > 0 ||
    Number.isFinite(numericValue(data.flySpeedFt, Number.NaN)) ||
    Number.isFinite(numericValue(data.baseArmorClass, Number.NaN)) ||
    Number.isFinite(numericValue(data.effectArmorClassBonus, Number.NaN)) ||
    Number.isFinite(numericValue(data.armorClassPenalty, Number.NaN)) ||
    Number.isFinite(numericValue(data.speedMultiplier, Number.NaN)) ||
    booleanValue(data.climbSpeedEqualsSpeed) ||
    booleanValue(data.flySpeedEqualsSpeed) ||
    booleanValue(data.waterBreathing) ||
    booleanValue(data.removesExhaustion) ||
    booleanValue(data.maximizeHitDiceHealing) ||
    booleanValue(data.noLethargyOnEnd) ||
    booleanValue(data.revivesDead) ||
    booleanValue(data.interruptsSpell) ||
    booleanValue(data.preventsReactions) ||
    Object.keys(recordValue(data.save)).length > 0
  );
}

function dnd5eSrdEffectRoll(actor: Actor, item: Item, data: Record<string, unknown>): QuickRoll {
  const prefix = item.type === "spell" ? "spell" : "item";
  return {
    id: `${prefix}-${item.id}-effect`,
    label: `${item.name} Effect`,
    formula: dnd5eSrdEffectFormula(data),
    metadata: dnd5eSrdEffectMetadata(actor, data, item.type === "spell")
  };
}

function dnd5eSrdEffectFormula(data: Record<string, unknown>): string {
  return stringValue(data.bonusFormula) || stringValue(data.penaltyFormula) || stringValue(data.recurringHealingFormula) || "0";
}

function dnd5eSrdEffectMetadata(actor: Actor, data: Record<string, unknown>, defaultSaveDcToSpellSaveDc: boolean): Record<string, unknown> {
  const metadata: Record<string, unknown> = { effectType: dnd5eSrdEffectType(data) };
  const spellLevel = numericValue(data.level, Number.NaN);
  const action = stringValue(data.action);
  const activation = stringValue(data.activation);
  const range = stringValue(data.range);
  const area = stringValue(data.area);
  const duration = stringValue(data.duration);
  const condition = stringValue(data.condition);
  const conditionDuration = stringValue(data.conditionDuration);
  const healing = stringValue(data.healing);
  const targetCount = numericValue(data.targetCount, Number.NaN);
  const save = dnd5eSrdEffectSaveMetadata(actor, data, defaultSaveDcToSpellSaveDc);
  const repeatSave = stringValue(data.repeatSave);
  const repeatSaveRecord = recordValue(data.repeatSave);
  const repeatSaveTiming = stringValue(data.repeatSaveTiming);
  const repeatSaveTimings = normalizeStringArray(data.repeatSaveTiming);
  const repeatSaveAbility = stringValue(data.repeatSaveAbility);
  const affectedRolls = normalizeStringArray(data.affectedRolls);
  const commandOptions = normalizeStringArray(data.commandOptions);
  const conditionsEnded = normalizeStringArray(data.conditionsEnded);
  const effects = normalizeStringArray(data.effects);
  const resistance = normalizeStringArray(data.resistance);
  const resistanceChoice = normalizeStringArray(data.resistanceChoice);
  const resistanceChoices = normalizeStringArray(data.resistanceChoices);
  const effectOptions = Array.isArray(data.effectOptions) ? data.effectOptions : [];
  const skillAdvantage = normalizeStringArray(data.skillAdvantage);
  const endsWhen = normalizeStringArray(data.endsWhen);
  const additionalConditions = normalizeStringArray(data.additionalConditions);
  const savingThrowAdvantage = normalizeStringArray(data.savingThrowAdvantage);
  const advantageAbilityChecks = normalizeStringArray(data.advantageAbilityChecks);
  const disadvantageAbilityChecks = normalizeStringArray(data.disadvantageAbilityChecks);
  const advantageSavingThrows = normalizeStringArray(data.advantageSavingThrows);
  const disadvantageSavingThrows = normalizeStringArray(data.disadvantageSavingThrows);
  const immunity = normalizeStringArray(data.immunity);
  const blocksDamageFrom = normalizeStringArray(data.blocksDamageFrom);
  const blockedBy = normalizeStringArray(data.blockedBy);
  const trigger = stringValue(data.trigger);
  if (Number.isFinite(spellLevel)) metadata.spellLevel = spellLevel;
  if (action) metadata.action = action;
  if (activation) metadata.activation = activation;
  if (range) metadata.range = range;
  if (area) metadata.area = area;
  if (duration) metadata.duration = duration;
  if (trigger) metadata.trigger = trigger;
  if (booleanValue(data.concentration)) metadata.concentration = true;
  if (booleanValue(data.ritual)) metadata.ritual = true;
  if (Number.isFinite(targetCount)) metadata.targetCount = targetCount;
  if (Object.keys(save).length > 0) metadata.save = save;
  if (repeatSave) metadata.repeatSave = repeatSave;
  if (Object.keys(repeatSaveRecord).length > 0) metadata.repeatSave = repeatSaveRecord;
  if (repeatSaveTiming) metadata.repeatSaveTiming = repeatSaveTiming;
  if (repeatSaveTimings.length > 0) metadata.repeatSaveTiming = repeatSaveTimings;
  if (repeatSaveAbility) metadata.repeatSaveAbility = repeatSaveAbility;
  if (condition) metadata.condition = condition;
  if (conditionDuration) metadata.conditionDuration = conditionDuration;
  if (affectedRolls.length > 0) metadata.affectedRolls = affectedRolls;
  if (commandOptions.length > 0) metadata.commandOptions = commandOptions;
  if (conditionsEnded.length > 0) metadata.conditionsEnded = conditionsEnded;
  if (effects.length > 0) metadata.effects = effects;
  if (resistance.length > 0) metadata.resistance = resistance;
  if (resistanceChoice.length > 0) metadata.resistanceChoice = resistanceChoice;
  if (resistanceChoices.length > 0) metadata.resistanceChoices = resistanceChoices;
  if (effectOptions.length > 0) metadata.effectOptions = cloneJsonRecord({ effectOptions }).effectOptions;
  if (skillAdvantage.length > 0) metadata.skillAdvantage = skillAdvantage;
  if (endsWhen.length > 0) metadata.endsWhen = endsWhen;
  if (additionalConditions.length > 0) metadata.additionalConditions = additionalConditions;
  if (savingThrowAdvantage.length > 0) metadata.savingThrowAdvantage = savingThrowAdvantage;
  if (advantageAbilityChecks.length > 0) metadata.advantageAbilityChecks = advantageAbilityChecks;
  if (disadvantageAbilityChecks.length > 0) metadata.disadvantageAbilityChecks = disadvantageAbilityChecks;
  if (advantageSavingThrows.length > 0) metadata.advantageSavingThrows = advantageSavingThrows;
  if (disadvantageSavingThrows.length > 0) metadata.disadvantageSavingThrows = disadvantageSavingThrows;
  if (immunity.length > 0) metadata.immunity = immunity;
  if (blocksDamageFrom.length > 0) metadata.blocksDamageFrom = blocksDamageFrom;
  if (blockedBy.length > 0) metadata.blockedBy = blockedBy;
  if (healing) metadata.healing = healing;
  const saveDc = numericValue(data.saveDc, Number.NaN);
  const escapeDc = numericValue(data.escapeDc, Number.NaN);
  const burstDc = numericValue(data.burstDc, Number.NaN);
  const pickDc = numericValue(data.pickDc, Number.NaN);
  const totalDurationHours = numericValue(data.totalDurationHours, Number.NaN);
  if (Number.isFinite(saveDc)) metadata.saveDc = saveDc;
  if (Number.isFinite(escapeDc)) metadata.escapeDc = escapeDc;
  if (Number.isFinite(burstDc)) metadata.burstDc = burstDc;
  if (Number.isFinite(pickDc)) metadata.pickDc = pickDc;
  if (Number.isFinite(totalDurationHours)) metadata.totalDurationHours = totalDurationHours;
  const upcastTargets = recordValue(data.upcastTargets);
  if (Object.keys(upcastTargets).length > 0) metadata.upcastTargets = upcastTargets;
  const abilityScoreSet = recordValue(data.abilityScoreSet);
  if (Object.keys(abilityScoreSet).length > 0) metadata.abilityScoreSet = abilityScoreSet;
  const spellcastingAbilityCheck = recordValue(data.spellcastingAbilityCheck);
  if (Object.keys(spellcastingAbilityCheck).length > 0) metadata.spellcastingAbilityCheck = spellcastingAbilityCheck;
  const additionalAction = recordValue(data.additionalAction);
  if (Object.keys(additionalAction).length > 0) metadata.additionalAction = additionalAction;
  const endingPenalty = recordValue(data.endingPenalty);
  if (Object.keys(endingPenalty).length > 0) metadata.endingPenalty = endingPenalty;
  const savingThrowPenalty = recordValue(data.savingThrowPenalty);
  if (Object.keys(savingThrowPenalty).length > 0) metadata.savingThrowPenalty = savingThrowPenalty;
  const flySpeedFt = numericValue(data.flySpeedFt, Number.NaN);
  const speedMultiplier = numericValue(data.speedMultiplier, Number.NaN);
  const baseArmorClass = numericValue(data.baseArmorClass, Number.NaN);
  const armorClassBonus = numericValue(data.effectArmorClassBonus, Number.NaN);
  const armorClassPenalty = numericValue(data.armorClassPenalty, Number.NaN);
  const dispelsSpellLevel = numericValue(data.dispelsSpellLevel, Number.NaN);
  const reviveHitPoints = numericValue(data.reviveHitPoints, Number.NaN);
  const consumedMaterialCostGp = numericValue(data.consumedMaterialCostGp, Number.NaN);
  const materialCostGp = numericValue(data.materialCostGp, Number.NaN);
  const somaticSpellFailureChancePercent = numericValue(data.somaticSpellFailureChancePercent, Number.NaN);
  const attackLimit = numericValue(data.attackLimit, Number.NaN);
  const teleportsFt = numericValue(data.teleportsFt, Number.NaN);
  const thoughtDetectionRangeFt = numericValue(data.thoughtDetectionRangeFt, Number.NaN);
  if (Number.isFinite(flySpeedFt)) metadata.flySpeedFt = flySpeedFt;
  if (booleanValue(data.canHover)) metadata.canHover = true;
  if (booleanValue(data.climbSpeedEqualsSpeed)) metadata.climbSpeedEqualsSpeed = true;
  if (booleanValue(data.flySpeedEqualsSpeed)) metadata.flySpeedEqualsSpeed = true;
  if (booleanValue(data.waterBreathing)) metadata.waterBreathing = true;
  if (booleanValue(data.fallWhenEndsUnlessCanStop)) metadata.fallWhenEndsUnlessCanStop = true;
  if (Number.isFinite(teleportsFt)) metadata.teleportsFt = teleportsFt;
  if (Number.isFinite(thoughtDetectionRangeFt)) metadata.thoughtDetectionRangeFt = thoughtDetectionRangeFt;
  if (Number.isFinite(speedMultiplier)) metadata.speedMultiplier = speedMultiplier;
  if (Number.isFinite(baseArmorClass)) metadata.baseArmorClass = baseArmorClass;
  const baseArmorClassAbility = stringValue(data.baseArmorClassAbility);
  if (baseArmorClassAbility) metadata.baseArmorClassAbility = baseArmorClassAbility;
  if (booleanValue(data.requiresNoArmor)) metadata.requiresNoArmor = true;
  if (Number.isFinite(armorClassBonus)) metadata.armorClassBonus = armorClassBonus;
  if (Number.isFinite(armorClassPenalty)) metadata.armorClassPenalty = armorClassPenalty;
  if (Number.isFinite(dispelsSpellLevel)) metadata.dispelsSpellLevel = dispelsSpellLevel;
  if (booleanValue(data.revivesDead)) metadata.revivesDead = true;
  const reviveWindow = stringValue(data.reviveWindow);
  if (reviveWindow) metadata.reviveWindow = reviveWindow;
  if (Number.isFinite(reviveHitPoints)) metadata.reviveHitPoints = reviveHitPoints;
  if (Number.isFinite(consumedMaterialCostGp)) metadata.consumedMaterialCostGp = consumedMaterialCostGp;
  if (Number.isFinite(materialCostGp)) metadata.materialCostGp = materialCostGp;
  if (booleanValue(data.cannotReviveOldAge)) metadata.cannotReviveOldAge = true;
  if (booleanValue(data.doesNotRestoreMissingBodyParts)) metadata.doesNotRestoreMissingBodyParts = true;
  if (booleanValue(data.upcastDispelLevelEqualsSlot)) metadata.upcastDispelLevelEqualsSlot = true;
  if (booleanValue(data.interruptsSpell)) metadata.interruptsSpell = true;
  if (booleanValue(data.wastedActionOnFailure)) metadata.wastedActionOnFailure = true;
  if (booleanValue(data.spellSlotNotExpendedOnFailure)) metadata.spellSlotNotExpendedOnFailure = true;
  if (booleanValue(data.includesTriggeringAttack)) metadata.includesTriggeringAttack = true;
  if (booleanValue(data.blocksVerbalComponents)) metadata.blocksVerbalComponents = true;
  if (booleanValue(data.preventsReactions)) metadata.preventsReactions = true;
  if (booleanValue(data.preventsActions)) metadata.preventsActions = true;
  if (booleanValue(data.preventsBonusActions)) metadata.preventsBonusActions = true;
  if (booleanValue(data.preventsAttacks)) metadata.preventsAttacks = true;
  if (booleanValue(data.preventsSpellcasting)) metadata.preventsSpellcasting = true;
  if (booleanValue(data.preventsSpeech)) metadata.preventsSpeech = true;
  if (booleanValue(data.preventsObjectInteraction)) metadata.preventsObjectInteraction = true;
  if (booleanValue(data.canPassThroughNarrowOpenings)) metadata.canPassThroughNarrowOpenings = true;
  if (booleanValue(data.liquidsTreatedAsSolid)) metadata.liquidsTreatedAsSolid = true;
  if (booleanValue(data.targetMustHearAndUnderstand)) metadata.targetMustHearAndUnderstand = true;
  if (booleanValue(data.excludesObviouslyHarmfulSuggestion)) metadata.excludesObviouslyHarmfulSuggestion = true;
  if (booleanValue(data.dispersedByStrongWind)) metadata.dispersedByStrongWind = true;
  if (booleanValue(data.actionOrBonusActionOnly)) metadata.actionOrBonusActionOnly = true;
  if (booleanValue(data.removesExhaustion)) metadata.removesExhaustion = true;
  if (booleanValue(data.maximizeHitDiceHealing)) metadata.maximizeHitDiceHealing = true;
  if (booleanValue(data.noLethargyOnEnd)) metadata.noLethargyOnEnd = true;
  if (Number.isFinite(somaticSpellFailureChancePercent)) metadata.somaticSpellFailureChancePercent = somaticSpellFailureChancePercent;
  if (Number.isFinite(attackLimit)) metadata.attackLimit = attackLimit;
  const spell = stringValue(data.spell);
  const spellEffect = stringValue(data.spellEffect);
  const endsCondition = stringValue(data.endsCondition);
  const giantType = stringValue(data.giantType);
  const giantTypes = normalizeStringArray(data.giantTypes);
  const targetAttitude = stringValue(data.targetAttitude);
  const targetCreatureType = stringValue(data.targetCreatureType);
  const sizeChange = stringValue(data.sizeChange);
  const damageBonusFormula = stringValue(data.damageBonusFormula);
  const damagePenaltyFormula = stringValue(data.damagePenaltyFormula);
  const sensor = stringValue(data.sensor);
  const senseOptions = normalizeStringArray(data.senseOptions);
  if (spell) metadata.spell = spell;
  if (spellEffect) metadata.spellEffect = spellEffect;
  if (endsCondition) metadata.endsCondition = endsCondition;
  if (giantType) metadata.giantType = giantType;
  if (giantTypes.length > 0) metadata.giantTypes = giantTypes;
  if (targetAttitude) metadata.targetAttitude = targetAttitude;
  if (targetCreatureType) metadata.targetCreatureType = targetCreatureType;
  if (sizeChange) metadata.sizeChange = sizeChange;
  if (damageBonusFormula) metadata.damageBonusFormula = damageBonusFormula;
  if (damagePenaltyFormula) metadata.damagePenaltyFormula = damagePenaltyFormula;
  if (sensor) metadata.sensor = sensor;
  if (senseOptions.length > 0) metadata.senseOptions = senseOptions;
  if (booleanValue(data.canSwitchSenseAsBonusAction)) metadata.canSwitchSenseAsBonusAction = true;
  const obscurement = stringValue(data.obscurement);
  const suggestionLimit = stringValue(data.suggestionLimit);
  if (obscurement) metadata.obscurement = obscurement;
  if (suggestionLimit) metadata.suggestionLimit = suggestionLimit;
  if (booleanValue(data.hostileTargetSaveAdvantage)) metadata.hostileTargetSaveAdvantage = true;
  if (booleanValue(data.endsWhenDamagedByCasterOrAllies)) metadata.endsWhenDamagedByCasterOrAllies = true;
  const recharge = stringValue(data.recharge);
  const summary = stringValue(data.summary);
  const speciesSpellResource = stringValue(data.speciesSpellResource);
  if (recharge) metadata.recharge = recharge;
  if (summary) metadata.summary = summary;
  if (booleanValue(data.speciesSpell)) metadata.speciesSpell = true;
  if (speciesSpellResource) metadata.freeCastResource = speciesSpellResource;
  return metadata;
}

function dnd5eSrdEffectType(data: Record<string, unknown>): string {
  if (stringValue(data.bonusFormula)) return "bonus";
  if (stringValue(data.penaltyFormula)) return "penalty";
  if (stringValue(data.recurringHealingFormula) || stringValue(data.healing)) return "healing";
  if (stringValue(data.condition)) return "condition";
  return "utility";
}

function dnd5eSrdEffectSaveMetadata(actor: Actor, data: Record<string, unknown>, defaultSaveDcToSpellSaveDc: boolean): Record<string, unknown> {
  const save = recordValue(data.save);
  const ability = stringValue(save.ability);
  if (!ability) return {};
  const dc = numericValue(save.dc, numericValue(data.saveDc, Number.NaN));
  const hasDc = Number.isFinite(dc);
  return {
    ...save,
    ability,
    ...(hasDc || defaultSaveDcToSpellSaveDc ? { dc: hasDc ? dc : dnd5eSrdSpellSaveDc(actor, stringValue(data.spellcastingAbility)) } : {})
  };
}

export function dnd5eSrdMonsterActionRolls(actor: Actor): QuickRoll[] {
  const statBlock = dnd5eSrdMonsterStatBlockFromActor(actor);
  if (!statBlock) return [];
  const actions = Array.isArray(statBlock.actions) ? statBlock.actions.flatMap((action) => [recordValue(action)]) : [];
  const conditionRoll = dnd5eSrdD20Automation(actor, "attack-roll");
  return actions.flatMap((action) => {
    const name = stringValue(action.name);
    if (!name) return [];
    const id = slugId(name);
    const rolls: QuickRoll[] = [];
    const attackBonus = numericValue(action.attackBonus, Number.NaN);
    if (Number.isFinite(attackBonus)) {
      rolls.push({
        id: `monster-${id}-attack`,
        label: `${name} Attack`,
        formula: `${conditionRoll.d20}${formatSignedNumber(attackBonus + conditionRoll.modifier)}`,
        ...(conditionRoll.metadata ? { metadata: conditionRoll.metadata } : {})
      });
    }
    const damageFormula = stringValue(action.damageFormula);
    if (damageFormula) {
      const metadata = dnd5eSrdMonsterActionDamageMetadata(action);
      rolls.push({
        id: `monster-${id}-damage`,
        label: `${name} Damage`,
        formula: damageFormula,
        ...(Object.keys(metadata).length > 0 ? { metadata } : {})
      });
    }
    const effectData = dnd5eSrdMonsterActionEffectData(action);
    if (dnd5eSrdHasEffectRollData(effectData)) {
      rolls.push({
        id: `monster-${id}-effect`,
        label: `${name} Effect`,
        formula: dnd5eSrdEffectFormula(effectData),
        metadata: dnd5eSrdEffectMetadata(actor, effectData, false)
      });
    }
    return rolls;
  });
}

function dnd5eSrdMonsterActionEffectData(action: Record<string, unknown>): Record<string, unknown> {
  const kind = stringValue(action.kind);
  return kind ? { ...action, action: kind } : action;
}

function dnd5eSrdMonsterActionDamageMetadata(action: Record<string, unknown>): Record<string, unknown> {
  const save = recordValue(action.save);
  const condition = stringValue(action.condition);
  const recharge = stringValue(action.recharge);
  const summary = stringValue(action.summary);
  const includeSummary = booleanValue(action.summaryMetadata);
  if (Object.keys(save).length === 0 && !condition && !recharge && !(summary && includeSummary)) return {};
  const metadata: Record<string, unknown> = {};
  const kind = stringValue(action.kind);
  const range = stringValue(action.range);
  const damageType = stringValue(action.damageType);
  if (kind) metadata.action = kind;
  if (range) metadata.range = range;
  if (damageType) metadata.damageType = damageType;
  if (Object.keys(save).length > 0) metadata.save = save;
  if (condition) metadata.condition = condition;
  if (recharge) metadata.recharge = recharge;
  if (summary) metadata.summary = summary;
  return metadata;
}

function dnd5eSrdMonsterStatBlockFromActor(actor: Actor): Record<string, unknown> | undefined {
  const monster = recordValue(actor.data.monster);
  const statBlock = recordValue(monster.statBlock);
  return Array.isArray(statBlock.actions) ? statBlock : undefined;
}

type Dnd5eSrdD20Context = "ability-check" | "skill-check" | "tool-check" | "saving-throw" | "attack-roll" | "initiative";

interface Dnd5eSrdConditionEffect {
  id: string;
  sourceId: string;
  data: Record<string, unknown>;
}

interface Dnd5eSrdD20Automation {
  d20: string;
  modifier: number;
  automaticFailure: boolean;
  metadata?: Record<string, unknown>;
}

function dnd5eSrdD20Automation(actor: Actor, context: Dnd5eSrdD20Context, ability?: string): Dnd5eSrdD20Automation {
  const conditions = normalizeConditionRecords(actor.data.conditions);
  const effects = dnd5eSrdConditionEffects(conditions);
  const advantageSources = dnd5eSrdD20RollModeSources(effects, context, ability, "advantage");
  const disadvantageSources = dnd5eSrdD20RollModeSources(effects, context, ability, "disadvantage");
  const automaticFailureSources =
    context === "saving-throw" && ability
      ? effects.filter((effect) => normalizeStringArray(effect.data.savingThrowsFail).includes(ability)).map((effect) => effect.sourceId)
      : [];
  const mode = advantageSources.length > 0 && disadvantageSources.length === 0 ? "advantage" : disadvantageSources.length > 0 && advantageSources.length === 0 ? "disadvantage" : "normal";
  const d20 = mode === "advantage" ? "2d20kh1" : mode === "disadvantage" ? "2d20kl1" : "1d20";
  const exhaustionLevel = dnd5eSrdExhaustionLevel(conditions);
  const modifier = exhaustionLevel > 0 ? exhaustionLevel * -2 : 0;
  const metadata: Record<string, unknown> = {};
  const conditionSources = uniqueStrings([...advantageSources, ...disadvantageSources, ...automaticFailureSources, ...(exhaustionLevel > 0 ? ["exhaustion"] : [])]);
  if (advantageSources.length > 0 || disadvantageSources.length > 0) metadata.conditionRollMode = mode;
  if (conditionSources.length > 0) metadata.conditionSources = conditionSources;
  if (automaticFailureSources.length > 0) metadata.automaticFailure = true;
  if (exhaustionLevel > 0) {
    metadata.exhaustionLevel = exhaustionLevel;
    metadata.conditionPenalty = modifier;
  }
  return {
    d20,
    modifier,
    automaticFailure: automaticFailureSources.length > 0,
    ...(Object.keys(metadata).length > 0 ? { metadata } : {})
  };
}

function dnd5eSrdFeatureAdvantageRoll(roll: Dnd5eSrdD20Automation, feature: string): Dnd5eSrdD20Automation {
  const conditionMode = stringValue(recordValue(roll.metadata).conditionRollMode);
  if (conditionMode === "disadvantage") {
    return {
      ...roll,
      d20: "1d20",
      metadata: { ...roll.metadata, feature, advantage: true, advantageCancelledByDisadvantage: true, conditionRollMode: "normal" }
    };
  }
  return {
    ...roll,
    d20: "2d20kh1",
    metadata: { ...roll.metadata, feature, advantage: true }
  };
}

function dnd5eSrdD20RollModeSources(effects: Dnd5eSrdConditionEffect[], context: Dnd5eSrdD20Context, ability: string | undefined, mode: "advantage" | "disadvantage"): string[] {
  return uniqueStrings(
    effects
      .filter((effect) => {
        if (context === "attack-roll") return effect.data.attackRolls === mode;
        if (context === "ability-check") return effect.data.abilityChecks === mode;
        if (context === "skill-check") return effect.data.skillChecks === mode || effect.data.abilityChecks === mode;
        if (context === "tool-check") return effect.data.toolChecks === mode || effect.data.abilityChecks === mode;
        if (context === "initiative") return effect.data.initiative === mode;
        if (context === "saving-throw" && ability) {
          const key = mode === "advantage" ? "savingThrowsAdvantage" : "savingThrowsDisadvantage";
          return normalizeStringArray(effect.data[key]).includes(ability);
        }
        return false;
      })
      .map((effect) => effect.sourceId)
  );
}

function dnd5eSrdConditionEffects(conditions: NormalizedConditionRecord[]): Dnd5eSrdConditionEffect[] {
  const effects: Dnd5eSrdConditionEffect[] = [];
  const visited = new Set<string>();
  const visit = (id: string, sourceId: string) => {
    const key = `${sourceId}:${id}`;
    if (visited.has(key)) return;
    visited.add(key);
    const entry = dnd5eSrdCompendiumEntry(id);
    if (!entry || entry.type !== "condition") return;
    const data = recordValue(entry.data);
    effects.push({ id, sourceId, data });
    for (const included of normalizeStringArray(data.includes)) visit(included, sourceId);
  };
  for (const condition of conditions) visit(condition.id, condition.id);
  return effects;
}

function dnd5eSrdExhaustionLevel(conditions: NormalizedConditionRecord[]): number {
  const exhaustion = conditions.find((condition) => condition.id === "exhaustion");
  return exhaustion ? clampInteger(exhaustion.level, 1, 6, 1) : 0;
}

export function dnd5eSrdAbilityCheck(actor: Actor, ability: string): QuickRoll {
  const modifier = genericFantasyAttributeModifier(actor, ability);
  const label = `${ability.charAt(0).toUpperCase()}${ability.slice(1)} Check`;
  const conditionRoll = dnd5eSrdD20Automation(actor, "ability-check", ability);
  return {
    id: `ability-${ability}`,
    label,
    formula: `${conditionRoll.d20}${formatSignedNumber(modifier + conditionRoll.modifier)}`,
    ...(conditionRoll.metadata ? { metadata: conditionRoll.metadata } : {})
  };
}

export function dnd5eSrdInitiativeRoll(actor: Actor): QuickRoll {
  const conditionRoll = dnd5eSrdD20Automation(actor, "initiative", "dexterity");
  const remarkableAthlete = dnd5eSrdHasChampionRemarkableAthlete(actor) ? dnd5eSrdFeatureAdvantageRoll(conditionRoll, "Remarkable Athlete") : conditionRoll;
  return {
    id: "initiative",
    label: "Initiative",
    formula: `${remarkableAthlete.d20}${formatSignedNumber(genericFantasyAttributeModifier(actor, "dexterity") + remarkableAthlete.modifier)}`,
    ...(remarkableAthlete.metadata ? { metadata: remarkableAthlete.metadata } : {})
  };
}

export function dnd5eSrdSavingThrow(actor: Actor, ability: string, items: Item[] = []): QuickRoll {
  const modifier = genericFantasyAttributeModifier(actor, ability);
  const proficiencyBonus = dnd5eSrdSaveProficiencies(actor).includes(ability) ? dnd5eSrdProficiencyBonus(actor) : 0;
  const itemBonus = dnd5eSrdEquippedItemNumericBonus(actor, items, "savingThrowBonus").total;
  const bonus = dnd5eSrdActorConditions(actor).some((condition) => condition.id === "blessed") ? "+1d4" : "";
  const label = `${ability.charAt(0).toUpperCase()}${ability.slice(1)} Save`;
  const dangerSense = ability === "dexterity" && dnd5eSrdHasDangerSense(actor) ? { advantage: true, feature: "Danger Sense", exceptConditions: ["Incapacitated"] } : {};
  const gnomishCunning = ["intelligence", "wisdom", "charisma"].includes(ability) && dnd5eSrdHasGnomeGnomishCunning(actor) ? { advantage: true, feature: "Gnomish Cunning", savingThrows: ["intelligence", "wisdom", "charisma"] } : {};
  const conditionRoll = dnd5eSrdD20Automation(actor, "saving-throw", ability);
  const metadata = Object.keys(dangerSense).length > 0 || Object.keys(gnomishCunning).length > 0 || itemBonus > 0 || conditionRoll.metadata ? { ...dangerSense, ...gnomishCunning, ...(itemBonus > 0 ? { itemBonus } : {}), ...conditionRoll.metadata } : undefined;
  return {
    id: `save-${ability}`,
    label,
    formula: conditionRoll.automaticFailure ? "0" : `${conditionRoll.d20}${formatSignedNumber(modifier + proficiencyBonus + itemBonus + conditionRoll.modifier)}${bonus}`,
    ...(metadata ? { metadata } : {})
  };
}

export function dnd5eSrdSkillCheck(actor: Actor, skillId: string): QuickRoll {
  const skill = dnd5eSrdSkillDefinition(skillId);
  const modifier = genericFantasyAttributeModifier(actor, skill.ability);
  const proficiencyMultiplier = dnd5eSrdSkillProficiencyMultiplier(actor, skill.id);
  const jackOfAllTradesBonus = proficiencyMultiplier === 0 && dnd5eSrdHasJackOfAllTrades(actor) ? Math.floor(dnd5eSrdProficiencyBonus(actor) / 2) : 0;
  const conditionRoll = dnd5eSrdD20Automation(actor, "skill-check", skill.ability);
  const skillRoll = skill.id === "athletics" && dnd5eSrdHasChampionRemarkableAthlete(actor) ? dnd5eSrdFeatureAdvantageRoll(conditionRoll, "Remarkable Athlete") : conditionRoll;
  const metadata = skillRoll.metadata || jackOfAllTradesBonus > 0 ? { ...skillRoll.metadata, ...(jackOfAllTradesBonus > 0 ? { feature: "Jack of All Trades", bonus: jackOfAllTradesBonus } : {}) } : undefined;
  return {
    id: `skill-${skill.id}`,
    label: `${skill.label} Check`,
    formula: `${skillRoll.d20}${formatSignedNumber(modifier + proficiencyMultiplier * dnd5eSrdProficiencyBonus(actor) + jackOfAllTradesBonus + skillRoll.modifier)}`,
    ...(metadata ? { metadata } : {})
  };
}

export function dnd5eSrdToolCheck(actor: Actor, toolId: string): QuickRoll {
  const tool = dnd5eSrdToolDefinition(toolId);
  const modifier = genericFantasyAttributeModifier(actor, tool.ability);
  const proficiencyMultiplier = dnd5eSrdToolProficiencyMultiplier(actor, tool.id);
  const conditionRoll = dnd5eSrdD20Automation(actor, "tool-check", tool.ability);
  return {
    id: `tool-${tool.id}`,
    label: `${tool.label} Check`,
    formula: `${conditionRoll.d20}${formatSignedNumber(modifier + proficiencyMultiplier * dnd5eSrdProficiencyBonus(actor) + conditionRoll.modifier)}`,
    ...(conditionRoll.metadata ? { metadata: conditionRoll.metadata } : {})
  };
}

export function dnd5eSrdDeathSavingThrow(actor: Actor): QuickRoll {
  const conditionRoll = dnd5eSrdD20Automation(actor, "saving-throw");
  const blessed = dnd5eSrdActorConditions(actor).some((condition) => condition.id === "blessed") ? "+1d4" : "";
  return {
    id: DND_5E_SRD_DEATH_SAVE_ROLL_ID,
    label: "Death Saving Throw",
    formula: `${conditionRoll.d20}${conditionRoll.modifier !== 0 ? formatSignedNumber(conditionRoll.modifier) : ""}${blessed}`,
    metadata: {
      ...conditionRoll.metadata,
      save: { dc: 10, success: "one success", failure: "one failure" },
      criticalSuccess: "regain 1 hit point",
      criticalFailure: "two failures",
      successesToStabilize: 3,
      failuresToDie: 3
    }
  };
}

export function dnd5eSrdConcentrationDc(damageTaken?: number): number {
  if (damageTaken === undefined || !Number.isFinite(damageTaken)) return 10;
  return Math.min(30, Math.max(10, Math.floor(Math.max(0, damageTaken) / 2)));
}

export function dnd5eSrdConcentrationCheck(actor: Actor, damageTaken?: number, items: Item[] = []): QuickRoll {
  const save = dnd5eSrdSavingThrow(actor, "constitution", items);
  const dc = dnd5eSrdConcentrationDc(damageTaken);
  return {
    ...save,
    id: DND_5E_SRD_CONCENTRATION_ROLL_ID,
    label: "Concentration Check",
    metadata: {
      ...save.metadata,
      concentration: true,
      save: { ability: "constitution", dc, rule: "DC 10 or half the damage taken, whichever is higher (max 30)" },
      ...(damageTaken !== undefined ? { triggerDamage: damageTaken } : {})
    }
  };
}

export function dnd5eSrdUnarmedStrike(actor: Actor): QuickRoll {
  const strengthModifier = genericFantasyAttributeModifier(actor, "strength");
  const dc = 8 + strengthModifier + dnd5eSrdProficiencyBonus(actor);
  return {
    id: DND_5E_SRD_UNARMED_STRIKE_ROLL_ID,
    label: "Unarmed Strike Damage",
    formula: String(Math.max(0, 1 + strengthModifier)),
    metadata: {
      damageType: "bludgeoning",
      grapple: { save: { ability: "strength or dexterity", dc }, targetSizeLimit: "no more than one size larger", escape: "repeat the save at the end of each of its turns" },
      shove: { save: { ability: "strength or dexterity", dc }, effect: "push 5 feet away or knock Prone", targetSizeLimit: "no more than one size larger" }
    }
  };
}

export function dnd5eSrdCoreCombatRolls(actor: Actor, items: Item[] = []): QuickRoll[] {
  return [dnd5eSrdDeathSavingThrow(actor), dnd5eSrdConcentrationCheck(actor, undefined, items), dnd5eSrdUnarmedStrike(actor)];
}

const dnd5eSrdSizeCarryMultipliers: Record<string, number> = { tiny: 0.5, small: 1, medium: 1, large: 2, huge: 4, gargantuan: 8 };

export function dnd5eSrdCarryingCapacity(actor: Actor): { carryPounds: number; dragPounds: number; sizeMultiplier: number } {
  const strengthScore = numericValue(recordValue(actor.data.attributes).strength, 10);
  const size = (stringValue(actor.data.size) ?? "medium").toLowerCase();
  const sizeMultiplier = dnd5eSrdSizeCarryMultipliers[size] ?? 1;
  return {
    carryPounds: Math.floor(strengthScore * 15 * sizeMultiplier),
    dragPounds: Math.floor(strengthScore * 30 * sizeMultiplier),
    sizeMultiplier
  };
}

export function dnd5eSrdFallingDamage(fallenFeet: number): QuickRoll {
  const dice = Math.min(20, Math.max(0, Math.floor(Math.max(0, fallenFeet) / 10)));
  return {
    id: "falling-damage",
    label: "Falling Damage",
    formula: dice > 0 ? `${dice}d6` : "0",
    metadata: { damageType: "bludgeoning", landsProne: dice > 0, rule: "1d6 per 10 feet fallen (max 20d6)" }
  };
}

export function dnd5eSrdJumpDistances(actor: Actor): { longJumpFt: number; highJumpFt: number; standingLongJumpFt: number; standingHighJumpFt: number } {
  const strengthScore = numericValue(recordValue(actor.data.attributes).strength, 10);
  const longJumpFt = Math.max(0, strengthScore);
  const highJumpFt = Math.max(0, 3 + genericFantasyAttributeModifier(actor, "strength"));
  return {
    longJumpFt,
    highJumpFt,
    standingLongJumpFt: Math.floor(longJumpFt / 2),
    standingHighJumpFt: Math.floor(highJumpFt / 2)
  };
}

export function dnd5eSrdCoverBonus(cover: "half" | "three-quarters" | "total"): { acBonus: number; dexteritySaveBonus: number; targetable: boolean } {
  if (cover === "half") return { acBonus: 2, dexteritySaveBonus: 2, targetable: true };
  if (cover === "three-quarters") return { acBonus: 5, dexteritySaveBonus: 5, targetable: true };
  return { acBonus: 0, dexteritySaveBonus: 0, targetable: false };
}

export const dnd5eSrdXpThresholds: readonly number[] = [0, 300, 900, 2700, 6500, 14000, 23000, 34000, 48000, 64000, 85000, 100000, 120000, 140000, 165000, 195000, 225000, 265000, 305000, 355000];

export function dnd5eSrdLevelForXp(xp: number): number {
  const safeXp = Number.isFinite(xp) ? Math.max(0, xp) : 0;
  let level = 1;
  for (let index = 0; index < dnd5eSrdXpThresholds.length; index += 1) {
    if (safeXp >= dnd5eSrdXpThresholds[index]!) level = index + 1;
  }
  return level;
}

export function dnd5eSrdXpForNextLevel(xp: number): number | undefined {
  const level = dnd5eSrdLevelForXp(xp);
  return level >= 20 ? undefined : dnd5eSrdXpThresholds[level];
}

export interface Dnd5eSrdXpProgress {
  xp: number;
  level: number;
  levelForXp: number;
  nextLevelXp?: number;
  previousLevelXp: number;
  readyToLevel: boolean;
}

export function dnd5eSrdXpProgress(actor: Actor): Dnd5eSrdXpProgress {
  const xp = Math.max(0, Math.floor(numericValue(actor.data.xp, 0)));
  const level = Math.max(1, Math.min(20, Math.floor(numericValue(actor.data.level, 1))));
  const levelForXp = dnd5eSrdLevelForXp(xp);
  const nextLevelXp = level >= 20 ? undefined : dnd5eSrdXpThresholds[level];
  const previousLevelXp = dnd5eSrdXpThresholds[level - 1] ?? 0;
  return { xp, level, levelForXp, nextLevelXp, previousLevelXp, readyToLevel: levelForXp > level };
}

export interface Dnd5eSrdClassLevel {
  className: string;
  level: number;
}

export interface Dnd5eSrdHitDicePool {
  className: string;
  size: string;
  current: number;
  max: number;
}

function dnd5eSrdHitDieFaces(size: string): number {
  const match = /^d(\d+)$/i.exec(size.trim());
  return match ? Number(match[1]) : 0;
}

function dnd5eSrdPrimaryClassForHitDice(actor: Actor, classes: Dnd5eSrdClassLevel[]): string {
  const actorClass = stringValue(actor.data.class);
  if (actorClass && classes.some((entry) => entry.className === actorClass)) return actorClass;
  return [...classes].sort((left, right) => right.level - left.level)[0]?.className ?? "Fighter";
}

function dnd5eSrdAggregateHitDiceFromPools(pools: Dnd5eSrdHitDicePool[], primaryClassName: string): { current: number; max: number; size: string } {
  return {
    current: pools.reduce((sum, pool) => sum + pool.current, 0),
    max: pools.reduce((sum, pool) => sum + pool.max, 0),
    size: dnd5eSrdHitDieSize(primaryClassName)
  };
}

function dnd5eSrdApplyHitDicePoolDelta(pools: Dnd5eSrdHitDicePool[], delta: number): Dnd5eSrdHitDicePool[] {
  if (delta === 0) return pools.map((pool) => ({ ...pool }));
  const next = pools.map((pool) => ({ ...pool }));
  const indexes = next
    .map((pool, index) => ({ index, faces: dnd5eSrdHitDieFaces(pool.size) }))
    .sort((left, right) => right.faces - left.faces || left.index - right.index)
    .map((entry) => entry.index);
  let remaining = Math.abs(delta);
  for (const index of indexes) {
    if (remaining <= 0) break;
    const pool = next[index]!;
    const room = delta > 0 ? pool.max - pool.current : pool.current;
    const amount = Math.min(room, remaining);
    if (amount <= 0) continue;
    pool.current += delta > 0 ? amount : -amount;
    remaining -= amount;
  }
  return next;
}

function dnd5eSrdLegacyHitDicePools(actor: Actor, classes: Dnd5eSrdClassLevel[]): Dnd5eSrdHitDicePool[] {
  const totalMax = classes.reduce((sum, entry) => sum + entry.level, 0);
  const hitDice = recordValue(actor.data.hitDice);
  const aggregateCurrent = Math.max(0, Math.min(totalMax, numericValue(hitDice.current, totalMax)));
  const primaryClassName = dnd5eSrdPrimaryClassForHitDice(actor, classes);
  const pools = classes.map((entry) => ({ className: entry.className, size: dnd5eSrdHitDieSize(entry.className), current: entry.level, max: entry.level }));
  let deficit = Math.max(0, totalMax - aggregateCurrent);
  const ordered = [primaryClassName, ...classes.map((entry) => entry.className).filter((className) => className !== primaryClassName)];
  for (const className of ordered) {
    if (deficit <= 0) break;
    const pool = pools.find((entry) => entry.className === className);
    if (!pool) continue;
    const spent = Math.min(pool.current, deficit);
    pool.current -= spent;
    deficit -= spent;
  }
  return pools;
}

function dnd5eSrdStoredHitDicePools(actor: Actor, classes: Dnd5eSrdClassLevel[]): Dnd5eSrdHitDicePool[] | undefined {
  if (!Array.isArray(actor.data.hitDicePools)) return undefined;
  const stored = actor.data.hitDicePools.flatMap((entry) => {
    const record = recordValue(entry);
    const className = stringValue(record.className);
    if (!className) return [];
    return [{ className, current: numericValue(record.current, 0) }];
  });
  if (stored.length === 0) return undefined;
  const pools = classes.map((entry) => {
    const current = Math.max(0, Math.min(entry.level, numericValue(stored.find((pool) => pool.className === entry.className)?.current, entry.level)));
    return { className: entry.className, size: dnd5eSrdHitDieSize(entry.className), current, max: entry.level };
  });
  const aggregate = recordValue(actor.data.hitDice);
  const max = pools.reduce((sum, pool) => sum + pool.max, 0);
  const desiredCurrent = Math.max(0, Math.min(max, numericValue(aggregate.current, pools.reduce((sum, pool) => sum + pool.current, 0))));
  const current = pools.reduce((sum, pool) => sum + pool.current, 0);
  return dnd5eSrdApplyHitDicePoolDelta(pools, desiredCurrent - current);
}

function dnd5eSrdHitDicePoolsForClasses(actor: Actor, classes: Dnd5eSrdClassLevel[]): Dnd5eSrdHitDicePool[] {
  if (classes.length <= 1) return [];
  return dnd5eSrdStoredHitDicePools(actor, classes) ?? dnd5eSrdLegacyHitDicePools(actor, classes);
}

export function dnd5eSrdHitDicePools(actor: Actor): Dnd5eSrdHitDicePool[] {
  return dnd5eSrdHitDicePoolsForClasses(actor, dnd5eSrdActorClassLevels(actor));
}

const dnd5eSrdFullCasterClasses = ["Bard", "Cleric", "Druid", "Sorcerer", "Wizard"];
const dnd5eSrdHalfCasterClasses = ["Paladin", "Ranger"];

export const dnd5eSrdMulticlassPrerequisites: Record<string, { all?: Array<{ ability: string; minimum: number }>; any?: Array<{ ability: string; minimum: number }> }> = {
  Barbarian: { all: [{ ability: "strength", minimum: 13 }] },
  Bard: { all: [{ ability: "charisma", minimum: 13 }] },
  Cleric: { all: [{ ability: "wisdom", minimum: 13 }] },
  Druid: { all: [{ ability: "wisdom", minimum: 13 }] },
  Fighter: { any: [{ ability: "strength", minimum: 13 }, { ability: "dexterity", minimum: 13 }] },
  Monk: { all: [{ ability: "dexterity", minimum: 13 }, { ability: "wisdom", minimum: 13 }] },
  Paladin: { all: [{ ability: "strength", minimum: 13 }, { ability: "charisma", minimum: 13 }] },
  Ranger: { all: [{ ability: "dexterity", minimum: 13 }, { ability: "wisdom", minimum: 13 }] },
  Rogue: { all: [{ ability: "dexterity", minimum: 13 }] },
  Sorcerer: { all: [{ ability: "charisma", minimum: 13 }] },
  Warlock: { all: [{ ability: "charisma", minimum: 13 }] },
  Wizard: { all: [{ ability: "intelligence", minimum: 13 }] }
};

export function dnd5eSrdActorClassLevels(actor: Actor): Dnd5eSrdClassLevel[] {
  const classesValue = actor.data.classes;
  if (Array.isArray(classesValue)) {
    const parsed = classesValue.flatMap((entry) => {
      const record = recordValue(entry);
      const className = stringValue(record.className) ?? stringValue(record.class);
      const level = Math.floor(numericValue(record.level, 0));
      return className && level > 0 ? [{ className, level }] : [];
    });
    if (parsed.length > 0) return parsed;
  }
  const className = stringValue(actor.data.class);
  return className ? [{ className, level: Math.max(1, Math.floor(numericValue(actor.data.level, 1))) }] : [];
}

export function dnd5eSrdMeetsMulticlassPrerequisite(actor: Actor, className: string): { eligible: boolean; requirement: string; missing: string[] } {
  const prerequisite = dnd5eSrdMulticlassPrerequisites[className];
  if (!prerequisite) return { eligible: false, requirement: "Unknown class", missing: [className] };
  const attributes = recordValue(actor.data.attributes);
  const scoreOf = (ability: string) => numericValue(attributes[ability], 10);
  const describe = (checks: Array<{ ability: string; minimum: number }>, joiner: string) => checks.map((check) => `${titleCaseWords(check.ability)} ${check.minimum}`).join(joiner);
  if (prerequisite.any) {
    const eligible = prerequisite.any.some((check) => scoreOf(check.ability) >= check.minimum);
    return {
      eligible,
      requirement: describe(prerequisite.any, " or "),
      missing: eligible ? [] : prerequisite.any.map((check) => titleCaseWords(check.ability))
    };
  }
  const checks = prerequisite.all ?? [];
  const missing = checks.filter((check) => scoreOf(check.ability) < check.minimum).map((check) => titleCaseWords(check.ability));
  return { eligible: missing.length === 0, requirement: describe(checks, " and "), missing };
}

export function dnd5eSrdCanMulticlassInto(actor: Actor, targetClassName: string): { eligible: boolean; reasons: string[] } {
  const reasons: string[] = [];
  for (const entry of dnd5eSrdActorClassLevels(actor)) {
    const current = dnd5eSrdMeetsMulticlassPrerequisite(actor, entry.className);
    if (!current.eligible) reasons.push(`Current class ${entry.className} requires ${current.requirement}`);
    if (entry.className === targetClassName) reasons.push(`Already leveled in ${targetClassName}`);
  }
  const target = dnd5eSrdMeetsMulticlassPrerequisite(actor, targetClassName);
  if (!target.eligible) reasons.push(`${targetClassName} requires ${target.requirement}`);
  return { eligible: reasons.length === 0, reasons };
}

export function dnd5eSrdMulticlassCasterLevel(classes: Dnd5eSrdClassLevel[]): number {
  return classes.reduce((total, entry) => {
    const level = Math.max(0, Math.floor(entry.level));
    if (dnd5eSrdFullCasterClasses.includes(entry.className)) return total + level;
    // Multiclass spellcasting adds HALF of Paladin/Ranger levels, rounded down.
    if (dnd5eSrdHalfCasterClasses.includes(entry.className)) return total + Math.floor(level / 2);
    return total;
  }, 0);
}

const dnd5eSrdMulticlassSlotTable: readonly number[][] = [
  [2],
  [3],
  [4, 2],
  [4, 3],
  [4, 3, 2],
  [4, 3, 3],
  [4, 3, 3, 1],
  [4, 3, 3, 2],
  [4, 3, 3, 3, 1],
  [4, 3, 3, 3, 2],
  [4, 3, 3, 3, 2, 1],
  [4, 3, 3, 3, 2, 1],
  [4, 3, 3, 3, 2, 1, 1],
  [4, 3, 3, 3, 2, 1, 1],
  [4, 3, 3, 3, 2, 1, 1, 1],
  [4, 3, 3, 3, 2, 1, 1, 1],
  [4, 3, 3, 3, 2, 1, 1, 1, 1],
  [4, 3, 3, 3, 3, 1, 1, 1, 1],
  [4, 3, 3, 3, 3, 2, 1, 1, 1],
  [4, 3, 3, 3, 3, 2, 2, 1, 1]
];

export function dnd5eSrdMulticlassSpellSlots(classes: Dnd5eSrdClassLevel[]): Record<string, { current: number; max: number; recovery: "long" }> {
  const casterLevel = Math.min(20, dnd5eSrdMulticlassCasterLevel(classes));
  if (casterLevel < 1) return {};
  const row = dnd5eSrdMulticlassSlotTable[casterLevel - 1] ?? [];
  return Object.fromEntries(row.map((max, index) => [`level${index + 1}`, { current: max, max, recovery: "long" as const }]));
}

export function dnd5eSrdMulticlassSpellcasting(actor: Actor): { classes: Dnd5eSrdClassLevel[]; casterLevel: number; slots: Record<string, { current: number; max: number; recovery: "long" }>; warlockLevels: number } {
  const classes = dnd5eSrdActorClassLevels(actor);
  return {
    classes,
    casterLevel: dnd5eSrdMulticlassCasterLevel(classes),
    slots: dnd5eSrdMulticlassSpellSlots(classes),
    warlockLevels: classes.filter((entry) => entry.className === "Warlock").reduce((total, entry) => total + entry.level, 0)
  };
}

