export function genericFantasyCompendiumEntry(entryId: string): GenericFantasyCompendiumEntry | undefined {
  return genericFantasyCompendium().find((entry) => entry.id === entryId);
}

interface Dnd5eSrdToolEntrySeed {
  id: string;
  name: string;
  ability: string;
  costGp: number;
  weightLb: number;
  summary?: string;
  toolId?: string;
  toolGroup?: string;
  variantOf?: string;
}

interface Dnd5eSrdGearEntrySeed {
  id: string;
  name: string;
  costGp: number;
  weightLb: number;
  summary?: string;
  data?: Record<string, unknown>;
}

interface Dnd5eSrdMagicItemEntrySeed {
  id: string;
  name: string;
  magicItemCategory: string;
  rarity: "common" | "uncommon" | "rare" | "very rare" | "legendary" | "artifact";
  summary?: string;
  requiresAttunement?: boolean;
  attunementRequirement?: string;
  data?: Record<string, unknown>;
}

function dnd5eSrdToolEntry(seed: Dnd5eSrdToolEntrySeed): GenericFantasyCompendiumEntry {
  return {
    id: seed.id,
    type: "item",
    name: seed.name,
    summary: seed.summary ?? "SRD tool entry for proficiency, inventory, and equipment purchasing.",
    data: {
      category: "tool",
      equipmentCategory: "tool",
      toolId: seed.toolId ?? seed.id,
      ability: seed.ability,
      costGp: seed.costGp,
      weightLb: seed.weightLb,
      ...(seed.toolGroup ? { toolGroup: seed.toolGroup } : {}),
      ...(seed.variantOf ? { variantOf: seed.variantOf } : {}),
      source: DND_5E_SRD_VERSION
    }
  };
}

function dnd5eSrdGearEntry(seed: Dnd5eSrdGearEntrySeed): GenericFantasyCompendiumEntry {
  return {
    id: seed.id,
    type: "item",
    name: seed.name,
    summary: seed.summary ?? "SRD adventuring gear with purchase cost and carried weight.",
    data: {
      category: "adventuring-gear",
      equipmentCategory: "gear",
      costGp: seed.costGp,
      weightLb: seed.weightLb,
      ...seed.data,
      source: DND_5E_SRD_VERSION
    }
  };
}

function dnd5eSrdMagicItemEntry(seed: Dnd5eSrdMagicItemEntrySeed): GenericFantasyCompendiumEntry {
  return {
    id: seed.id,
    type: "item",
    name: seed.name,
    summary: seed.summary ?? "SRD magic item entry with rarity, attunement, and VTT automation metadata.",
    data: {
      category: "magic-item",
      equipmentCategory: "magic-item",
      magicItem: true,
      magicItemCategory: seed.magicItemCategory,
      rarity: seed.rarity,
      ...(seed.requiresAttunement ? { requiresAttunement: true } : {}),
      ...(seed.attunementRequirement ? { attunementRequirement: seed.attunementRequirement } : {}),
      ...dnd5eSrdMagicItemCraftingMetadata(seed.rarity, booleanValue(seed.data?.consumable)),
      ...seed.data,
      source: DND_5E_SRD_VERSION
    }
  };
}

function dnd5eSrdMagicItemCraftingMetadata(rarity: Dnd5eSrdMagicItemEntrySeed["rarity"], consumable = false): Record<string, unknown> {
  if (rarity === "artifact") {
    return { craftable: false };
  }
  const table: Record<Exclude<Dnd5eSrdMagicItemEntrySeed["rarity"], "artifact">, { craftingDays: number; craftingCostGp: number }> = {
    common: { craftingDays: 5, craftingCostGp: 50 },
    uncommon: { craftingDays: 10, craftingCostGp: 200 },
    rare: { craftingDays: 50, craftingCostGp: 2000 },
    "very rare": { craftingDays: 125, craftingCostGp: 20000 },
    legendary: { craftingDays: 250, craftingCostGp: 100000 }
  };
  const entry = table[rarity];
  return consumable ? { craftingDays: entry.craftingDays / 2, craftingCostGp: entry.craftingCostGp / 2 } : entry;
}

