function dnd5eSrdDraconicSpells(level: number): Array<{ sorcererLevel: number; spells: string[] }> {
  const normalized = Math.max(1, Math.floor(level));
  const spells: Array<{ sorcererLevel: number; spells: string[] }> = [];
  if (normalized >= 3) spells.push({ sorcererLevel: 3, spells: ["alter-self", "chromatic-orb", "command", "dragons-breath"] });
  if (normalized >= 5) spells.push({ sorcererLevel: 5, spells: ["fear", "fly"] });
  if (normalized >= 7) spells.push({ sorcererLevel: 7, spells: ["arcane-eye", "charm-monster"] });
  if (normalized >= 9) spells.push({ sorcererLevel: 9, spells: ["legend-lore", "summon-dragon"] });
  return spells;
}

